sys_ux_data_broker_transform.script:
function transform({sysId}){  
    const snapshot = new global.GlideQuery('x_snc_pb_core_snapshot')
    .where("sys_id", sysId)
    .selectOne('db_image$DISPLAY', 'image$DISPLAY', 'request.email', 'request.sys_id')
    .get();

    let { db_image$DISPLAY : publicImagePath, image$DISPLAY : privateImagePath } = snapshot;
    const request = (({ sys_id : sysId, email }) => ({sysId, email}))(snapshot.request);

	// If the "db_image" value is set, use as the public path.  If not, use the "image" field value.
	return ({ imagePath : publicImagePath || privateImagePath, isPublic : !!publicImagePath, request });
}
